import Link from "next/link";

export type ProjectCardProps = {
  title: string;
  client: string;
  description: string;
  year: string;
  scope: string;
  platform: string;
  href?: string;
  themeColor?: string; // Hex color for glow effect (e.g., "#ffa100")
};

// Figma image asset for the case study card.
// This is a temporary shared image until per-project artwork is wired up.
const CASE_STUDY_IMAGE = "/case-study-image.png";

export function ProjectCard({
  title,
  client,
  description,
  year,
  scope,
  platform,
  href,
  themeColor = "#ffa100",
}: ProjectCardProps) {
  const Wrapper = href ? Link : "div";

  const wrapperProps = href
    ? { href: href as string }
    : ({} as Record<string, never>);

  // Convert hex to RGB for glow effect
  const hexToRgb = (hex: string) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result
      ? {
          r: parseInt(result[1], 16),
          g: parseInt(result[2], 16),
          b: parseInt(result[3], 16),
        }
      : { r: 255, g: 161, b: 0 };
  };

  const rgb = hexToRgb(themeColor);

  return (
    <Wrapper
      {...wrapperProps}
      className="relative flex flex-col gap-5 rounded-[24px] bg-zinc-950/70 p-5 shadow-[0_18px_60px_rgba(0,0,0,0.85)] transition-shadow duration-300"
    >
      {/* Type pills row (right aligned) */}
      <div className="relative z-10 flex justify-end">
        <div className="flex flex-wrap gap-2 text-[0.65rem] font-medium uppercase tracking-[0.16em] text-zinc-200/90">
          {scope && (
            <span className="rounded-md bg-zinc-900/70 px-3 py-1">
              {scope}
            </span>
          )}
          {platform && (
            <span className="rounded-md bg-zinc-900/70 px-3 py-1">
              {platform}
            </span>
          )}
          {year && (
            <span className="rounded-md bg-zinc-900/70 px-3 py-1">
              {year}
            </span>
          )}
        </div>
      </div>

      {/* Image card */}
      <div
        className="group relative rounded-[18px] bg-zinc-900/60 p-2 border border-white/15 transition-[box-shadow] duration-300"
        style={{
          boxShadow: `0 0 0 0 rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`,
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.boxShadow = `0 0 40px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.6), 0 0 80px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.4)`;
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.boxShadow = `0 0 0 0 rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`;
        }}
      >
        <div
          className="group/inner relative aspect-[4/3] rounded-[10px] transition-[box-shadow] duration-300"
          style={{
            boxShadow: `0 0 0 0 rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`,
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.boxShadow = `0 0 30px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.5), 0 0 60px rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0.3)`;
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.boxShadow = `0 0 0 0 rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`;
          }}
        >
          <img
            src={CASE_STUDY_IMAGE}
            alt={title}
            className="project-card-image size-full object-cover transition-all duration-300 border border-white/15 rounded-[10px]"
          />
          {/* Theme color overlay on hover */}
          <div
            className="pointer-events-none absolute inset-0 opacity-0 transition-opacity duration-300 group-hover/inner:opacity-20 rounded-[10px]"
            style={{
              backgroundColor: themeColor,
              mixBlendMode: "overlay",
            }}
          />
        </div>
      </div>

      {/* Description block */}
      <div className="relative z-10 space-y-2 pt-1 text-zinc-200">
        <h3
          className="text-[24px] font-semibold text-zinc-50"
          style={{ fontFamily: "var(--font-playfair)" }}
        >
          {title}
        </h3>
        <p className="text-xs text-zinc-300/90">{client}</p>
        <p className="text-sm text-zinc-300/90">{description}</p>
      </div>

      {href && (
        <span className="relative z-10 mt-1 inline-flex items-center text-[0.65rem] font-medium uppercase tracking-[0.2em] text-zinc-400">
          View case study
          <span className="ml-2 h-px w-6 bg-zinc-500 transition-all" />
        </span>
      )}
    </Wrapper>
  );
}

